// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  // Compute weather icon/emoji from condition
  const getWeatherIcon = useCallback((condition: string): string => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
    if (lowerCondition.includes('cloud')) return '☁️';
    if (lowerCondition.includes('rain')) return '🌧️';
    if (lowerCondition.includes('snow')) return '❄️';
    if (lowerCondition.includes('storm')) return '⛈️';
    if (lowerCondition.includes('wind')) return '💨';
    return '🌤️'; // default
  }, []);

  return {
    getWeatherIcon,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const weatherIcon = state.getWeatherIcon(props.condition);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* MAIN WEATHER CARD */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={24}>
            {/* HEADER: City and Condition */}
            <Stack gap={8}>
              <Heading level={2}>{props.city}</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {props.condition}
              </Text>
            </Stack>

            {/* TEMPERATURE DISPLAY */}
            <Stack gap={16} align="center" justify="center">
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
                {props.temperature}°{props.unit}
              </Text>
              <Text size="2xl" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {weatherIcon}
              </Text>
            </Stack>

            <Divider />

            {/* WEATHER DETAILS: Humidity and Wind */}
            <Row gap={24} justify="between" align="center">
              <Stack gap={4} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.humidity}%
                </Text>
              </Stack>
              <Stack gap={4} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.windSpeed} m/s
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST STRIP */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="sm" padding={16} radius="lg">
            <Stack gap={8} direction="vertical">
              <Heading level={4}>5-Day Forecast</Heading>
              <Row gap={12} wrap justify="start" align="center">
                {props.forecast.map((day, index) => (
                  <Box
                    key={index}
                    padding={12}
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    style={{ flex: '0 1 100px', textAlign: 'center' }}
                  >
                    <Stack gap={6} align="center" justify="center">
                      {day.day && day.icon !== undefined && day.high !== undefined && day.low !== undefined ? (
                        <>
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {day.day}
                          </Text>
                          <Text size="lg">
                            {day.icon}
                          </Text>
                          <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                            {day.high}°{props.unit} / {day.low}°{props.unit}
                          </Text>
                        </>
                      ) : null}
                    </Stack>
                  </Box>
                ))}
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // Form state
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Validation helpers
  const validateEmail = useCallback((value: string) => {
    if (!value) {
      setEmailError('Email is required');
      return false;
    }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(value)) {
      setEmailError('Please enter a valid email');
      return false;
    }
    setEmailError('');
    return true;
  }, []);

  const validateName = useCallback((value: string) => {
    if (!value.trim()) {
      setNameError('Name is required');
      return false;
    }
    setNameError('');
    return true;
  }, []);

  // Check if current step is valid
  const isStep1Valid = useCallback(() => {
    return validateName(name) && validateEmail(email);
  }, [name, email, validateName, validateEmail]);

  const isStep2Valid = satisfaction !== '';

  const isStep3Valid = features.length > 0;

  const isCurrentStepValid = useCallback(() => {
    switch (currentStep) {
      case 1: return isStep1Valid();
      case 2: return isStep2Valid;
      case 3: return isStep3Valid;
      case 4: return true; // Review step has no validation
      default: return false;
    }
  }, [currentStep, isStep1Valid, isStep2Valid, isStep3Valid]);

  // Handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid()) return;
    if (currentStep === 2 && !isStep2Valid) return;
    if (currentStep === 3 && !isStep3Valid) return;

    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, isStep1Valid, isStep2Valid, isStep3Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    if (!isCurrentStepValid()) return;

    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments,
    });
  }, [name, email, satisfaction, features, comments, submit, isCurrentStepValid]);

  const handleFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setFeatures(prev =>
      checked ? [...prev, feature] : prev.filter(f => f !== feature)
    );
  }, []);

  return {
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    setFeatures,
    comments,
    setComments,
    nameError,
    emailError,
    handleNext,
    handleBack,
    handleSubmit,
    handleFeatureToggle,
    validateName,
    validateEmail,
    isCurrentStepValid,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* PROGRESS BAR */}
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2}>Multi-Step Survey</Heading>
            <Text variant="label">Step {state.currentStep} of 4</Text>
          </Stack>
          <Progress
            value={state.currentStep}
            max={4}
            variant="default"
            size="md"
            showLabel={false}
          />
        </Stack>

        {/* STEP 1: NAME & EMAIL */}
        {state.currentStep === 1 && (
          <Card shadow="md" padding={24}>
            <Stack gap={16}>
              <Heading level={3}>Your Information</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Please provide your name and email address.
              </Text>
              <Stack gap={12}>
                <Input
                  label="Name"
                  value={state.name}
                  onChange={(value) => {
                    state.setName(value);
                    if (value.trim()) state.validateName(value);
                  }}
                  placeholder="John Doe"
                  required
                  error={state.nameError}
                />
                <Input
                  label="Email"
                  type="email"
                  value={state.email}
                  onChange={(value) => {
                    state.setEmail(value);
                    if (value) state.validateEmail(value);
                  }}
                  placeholder="john@example.com"
                  required
                  error={state.emailError}
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 2: SATISFACTION */}
        {state.currentStep === 2 && (
          <Card shadow="md" padding={24}>
            <Stack gap={16}>
              <Heading level={3}>How Satisfied Are You?</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Please rate your satisfaction on a scale of 1-5.
              </Text>
              <RadioGroup
                label="Satisfaction Rating"
                value={state.satisfaction}
                onChange={(value) => state.setSatisfaction(value)}
                direction="vertical"
                options={(props.satisfactionLabels || []).map((label, index) => ({
                  value: String(index + 1),
                  label: `${index + 1} - ${label}`,
                }))}
              />
            </Stack>
          </Card>
        )}

        {/* STEP 3: FEATURE INTERESTS */}
        {state.currentStep === 3 && (
          <Card shadow="md" padding={24}>
            <Stack gap={16}>
              <Heading level={3}>Which Features Interest You?</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select all features that interest you. At least one is required.
              </Text>
              <Stack gap={12}>
                {(props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={state.features.includes(feature)}
                    onChange={(checked) => state.handleFeatureToggle(feature, checked)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 4: COMMENTS */}
        {state.currentStep === 4 && (
          <Card shadow="md" padding={24}>
            <Stack gap={16}>
              <Heading level={3}>Additional Comments</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Please share any additional feedback. (Optional, max 500 characters)
              </Text>
              <TextArea
                label="Comments"
                value={state.comments}
                onChange={(value) => state.setComments(value.slice(0, 500))}
                placeholder="Your comments here..."
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* STEP 5: REVIEW */}
        {state.currentStep === 5 && (
          <Card shadow="md" padding={24}>
            <Stack gap={16}>
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap={12}>
                <Box paddingY={8} paddingX={0}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Name
                  </Text>
                  <Text variant="body">{state.name}</Text>
                </Box>
                <Divider />
                <Box paddingY={8} paddingX={0}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Email
                  </Text>
                  <Text variant="body">{state.email}</Text>
                </Box>
                <Divider />
                <Box paddingY={8} paddingX={0}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Satisfaction Rating
                  </Text>
                   <Text variant="body">
                     {state.satisfaction ? `${state.satisfaction} - ${(props.satisfactionLabels || [])[parseInt(state.satisfaction, 10) - 1] || 'N/A'}` : 'Not selected'}
                   </Text>
                 </Box>
                 <Divider />
                 <Box paddingY={8} paddingX={0}>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                     Feature Interests
                   </Text>
                   <Stack gap={4} direction="horizontal" wrap>
                     {state.features.map((feature) => (
                       <Badge key={feature} variant="primary" size="sm">
                         {feature}
                       </Badge>
                     ))}
                   </Stack>
                 </Box>
                 <Divider />
                 <Box paddingY={8} paddingX={0}>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                     Comments
                   </Text>
                   <Text variant="body">
                     {state.comments || '(No comments provided)'}
                   </Text>
                 </Box>
               </Stack>
             </Stack>
           </Card>

        {/* NAVIGATION BUTTONS */}
        <Stack direction="horizontal" justify="between" gap={12}>
          <Button
            variant="outline"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
          <Stack direction="horizontal" gap={8}>
            {state.currentStep < 4 && (
              <Button
                variant="primary"
                onClick={state.handleNext}
                disabled={!state.isCurrentStepValid()}
              >
                Next
              </Button>
            )}
            {state.currentStep === 4 && (
              <Button
                variant="primary"
                onClick={() => state.setCurrentStep(5)}
              >
                Review
              </Button>
            )}
            {state.currentStep === 5 && (
              <Button
                variant="primary"
                onClick={state.handleSubmit}
              >
                Submit
              </Button>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { useAction, useStream } from '@ggui-ai/wire';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State for tasks and UI
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');

  // Sync stream updates into local tasks
  React.useEffect(() => {
    if (!taskChanged || !taskChanged.latest) return;
    const event = taskChanged.latest;
    // Skip events from current session to avoid double-processing
    if (!event.task || !event.task.id) return;
    if (event.action === 'create' && event.task) {
      setTasks(prev => [...prev, { id: event.task!.id || Date.now().toString(), ...event.task }]);
    } else if (event.action === 'move' && event.task) {
      // Skip update if task is currently being edited locally
      if (event.task.id === editingTaskId) return;
      setTasks(prev => prev.map(t => t.id === event.task!.id ? { ...t, ...event.task } : t));
    } else if (event.action === 'edit' && event.task) {
      // Skip update if task is currently being edited locally
      if (event.task.id === editingTaskId) return;
      setTasks(prev => prev.map(t => t.id === event.task!.id ? { ...t, ...event.task } : t));
    } else if (event.action === 'delete' && event.task) {
      setTasks(prev => prev.filter(t => t.id !== event.task!.id));
    }
  }, [taskChanged.latest, editingTaskId]);

  // Get tasks by column
  const tasksByColumn = useCallback((columnId: string) => {
    return tasks.filter(t => t.column === columnId);
  }, [tasks]);

  // Count completed tasks (in 'done' column)
  const completedCount = useCallback(() => {
   const completedCount = useCallback(() => {
     const doneColumnId = (props.columns || []).find(c => c.id === 'done')?.id || 'done';
     return tasks.filter(t => t.column === doneColumnId).length;
   }, [tasks, props.columns]);

  // Handle adding new task
  // Handle adding new task
  const handleAddTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: Date.now().toString(),
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
      };
      setTasks(prev => [...prev, newTask]);
       taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingToColumn(null);
    }
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  // Handle moving task
  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: targetColumn } : t));
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  // Handle editing task title
  const handleEditTask = useCallback((taskId: string) => {
    if (editingTaskTitle.trim() && taskId) {
      setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: editingTaskTitle } : t));
       taskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo' } });
      setEditingTaskId(null);
      setEditingTaskTitle('');
    }
  }, [editingTaskTitle, taskUpdate, tasks]);

  return {
    tasks,
    addingToColumn,
    setAddingToColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    editingTaskId,
    setEditingTaskId,
    editingTaskTitle,
    setEditingTaskTitle,
    taskUpdate,
    taskChanged,
    tasksByColumn,
    completedCount,
    handleAddTask,
    handleMoveTask,
    handleEditTask,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const priorityColors = {
    low: 'success',
    medium: 'warning',
    high: 'error',
  } as const;

  return (
    <Container maxWidth='3xl' padding={24}>
      <Stack gap={24}>
        {/* HEADER WITH SUMMARY */}
        <Stack gap={8}>
          <Heading level={1}>Task Board</Heading>
          <Box
            background='var(--ggui-color-primary-50, #f0f9ff)'
            borderRadius='var(--ggui-shape-radius-md, 8px)'
            padding={16}
          >
            <Row gap={24} justify='start' align='center'>
              <Stack gap={4} align='center'>
                <Text variant='label' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                  Total Tasks
                </Text>
                <Heading level={3}>{state.tasks.length}</Heading>
              </Stack>
              <Divider orientation='vertical' margin={0} color='var(--ggui-color-outline, #d4d4d8)' />
              <Stack gap={4} align='center'>
                <Text variant='label' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                  Completed
                </Text>
                <Heading level={3}>{state.completedCount()}</Heading>
              </Stack>
            </Row>
          </Box>
        </Stack>

        {/* KANBAN BOARD */}
        <Row gap={16} align='start' wrap>
          {(props.columns || []).map(column => {
            const columnId = column.id || 'todo';
            const columnTasks = state.tasksByColumn(columnId);
            return (
              <Card
                key={columnId}
                padding={16}
                shadow='sm'
                radius='md'
                style={{ minWidth: '300px', flex: '0 1 300px', maxHeight: '70vh', overflowY: 'auto' }}
              >
                  {/* COLUMN HEADER */}
                  <Stack gap={8}>
                    <Row gap={8} align='center' justify='between'>
                      <Heading level={4}>{column.name}</Heading>
                      <Badge variant='default' size='sm'>
                        {columnTasks.length}
                      </Badge>
                    </Row>
                    <Divider orientation='horizontal' margin={0} color='var(--ggui-color-outlineVariant, #e4e4e7)' />
                  </Stack>

                  {/* TASK LIST */}
                  <Stack gap={8}>
                    {columnTasks.map(task => {
                      if (!task.id) return null;
                      return (
                        <Card
                          key={task.id}
                          padding={12}
                          shadow='none'
                          border={true}
                          radius='sm'
                          style={{ backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}
                        >
                          <Stack gap={8}>
                            {/* TASK TITLE (EDITABLE) */}
                            {state.editingTaskId === task.id ? (
                              <Row gap={6}>
                                <Input
                                  label=''
                                  value={state.editingTaskTitle}
                                  onChange={state.setEditingTaskTitle}
                                  size='sm'
                                  placeholder='Task title'
                                />
                                <Button
