// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by search query (case-insensitive, matches name or symbol)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        (el.name?.toLowerCase().includes(query) ?? false) ||
        (el.symbol?.toLowerCase().includes(query) ?? false)
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map((el) => el.category).filter(Boolean));
    return Array.from(cats);
  }, [props.elements]);

  // Category to color mapping using design tokens
  const categoryColorMap = useCallback((category: string | undefined) => {
    const colorMap: Record<string, string> = {
      'alkali-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-200, #bae6fd)',
      'lanthanide': 'var(--ggui-color-info-100, #cffafe)',
      'actinide': 'var(--ggui-color-info-200, #a5f3fc)',
      'transition-metal': 'var(--ggui-color-warning-100, #fef3c7)',
      'metal': 'var(--ggui-color-warning-200, #fde68a)',
      'semimetal': 'var(--ggui-color-error-100, #fee2e2)',
      'nonmetal': 'var(--ggui-color-success-100, #dcfce7)',
      'halogen': 'var(--ggui-color-success-200, #bbf7d0)',
      'noble-gas': 'var(--ggui-color-primary-50, #f0f9ff)',
    };
    return colorMap[category ?? ''] || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  }, []);

  const handleSearch = useCallback((query: string) => {
    setSearchQuery(query);
  }, []);

  const handleElementClick = useCallback((element: typeof props.elements[0]) => {
    setSelectedElement(element);
  }, []);

  return {
    searchQuery,
    filteredElements,
    selectedElement,
    categories,
    handleSearch,
    handleElementClick,
    categoryColorMap,
  };
}

