  React.useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Update typing indicator from stream
  React.useEffect(() => {
    if (typing.latest) {
      setTypingIndicator(typing.latest);
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputText, timestamp });
      // Add message to local list immediately
      setMessages((prev) => [
        ...prev,
        { sender: props.currentUser, text: inputText, timestamp }
      ]);
      setInputText('');
    }
  }, [inputText, sendMessage, props.currentUser]);

  return {
    messages,
    setMessages,
    inputText,
    setInputText,
    handleSendMessage,
    typingIndicator,
    messagesEndRef
  };
}

export default function Component(props: Props) {
