                      >
                        <Text
                          variant="body"
                          color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                        >
                          {msg.text || ''}
                        </Text>
                      </Box>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" size="xs">
                        {timestamp}
                      </Text>
                    </Stack>
                  );
                })}
                <div ref={state.messagesEndRef} />
              </>
            )}
          </Box>

          <Divider orientation="horizontal" margin={0} />

          {/* INPUT AREA */}
          <Box paddingX={24} paddingY={16}>
            <Stack gap={8} direction="horizontal" align="center">
              <Input
                label="Message input"
                placeholder="Type your message..."
                value={state.inputText}
                onChange={state.setInputText}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    state.handleSendMessage();
                  }
                }}
              />
              <Button
                variant="primary"
                size="md"
                disabled={!state.inputText.trim()}
                onClick={state.handleSendMessage}
              >
                Send
              </Button>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

