import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for displaying stocks with live updates
  const [stocks, setStocks] = useState(() => props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());

  // Merge stream updates into displayed stocks
  React.useEffect(() => {
    if (priceUpdate.latest) {
      setStocks((prevStocks) => {
        return prevStocks.map((stock) => {
          if (stock.symbol === priceUpdate.latest?.symbol) {
            // Trigger flash animation
            setFlashingSymbols((prev) => {
              const next = new Set(prev);
              next.add(stock.symbol!);
              // Clear the flashing state after animation completes (500ms)
              setTimeout(() => {
                setFlashingSymbols((s) => {
                  const updated = new Set(s);
                  updated.delete(stock.symbol!);
                  return updated;
                });
              }, 500);
              return next;
            });
            setLastUpdated(new Date());
            return {
              ...stock,
              price: priceUpdate.latest.price ?? stock.price,
              change: priceUpdate.latest.change ?? stock.change,
              changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
      });
    }
  }, [priceUpdate.latest]);

  return { stocks, lastUpdated, flashingSymbols, marketStatus };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const formattedTime = state.lastUpdated.toLocaleTimeString('en-US', {
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1}>Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formattedTime}
            </Text>
          </Stack>
        </Stack>

        {/* STOCK CARDS GRID */}
        <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
          {state.stocks.map((stock) => {
            const isPositive = (stock.changePercent ?? 0) >= 0;
            const isFlashing = state.flashingSymbols.has(stock.symbol || '');
            const flashStyle = isFlashing
              ? {
                  animation: 'ggui-fadeIn 500ms ease-out',
                  backgroundColor: isPositive
                    ? 'var(--ggui-color-success-100, #dcfce7)'
                    : 'var(--ggui-color-error-100, #fee2e2)',
                }
              : undefined;

            return (
              <Card
                key={stock.symbol}
                padding={16}
                shadow="sm"
                border={true}
                radius="lg"
                style={{
                  borderColor: isPositive
                    ? 'var(--ggui-color-success-300, #86efac)'
                    : 'var(--ggui-color-error-300, #fca5a5)',
                  ...flashStyle,
                }}
              >
                <Stack gap={12}>
                  {/* Ticker Symbol - Large and Bold */}
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                    {stock.symbol}
                  </Heading>

                  {/* Company Name */}
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {stock.name}
                  </Text>

                  {/* Current Price */}
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    ${(stock.price ?? 0).toFixed(2)}
                  </Text>

                  {/* Change Amount and Percentage with Arrow */}
                  <Stack direction="horizontal" gap={8} align="center">
                    <Icon
                      name={isPositive ? '▲' : '▼'}
                      size={16}
                      color={
                        isPositive
                          ? 'var(--ggui-color-success-500, #22c55e)'
                          : 'var(--ggui-color-error-500, #ef4444)'
                      }
                    />
                    <Text
                      variant="body"
                      weight="semibold"
                      color={
                        isPositive
                          ? 'var(--ggui-color-success-600, #16a34a)'
                          : 'var(--ggui-color-error-600, #dc2626)'
                      }
                    >
                      {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)} ({(stock.changePercent ?? 0).toFixed(2)}%)
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

