                      ))}
                    </Stack>
                  </Stack>
                </Stack>
              </Stack>
            )}

            {/* STEP 3: REVIEW & CONFIRM */}
            {/* STEP 3: REVIEW & CONFIRM */}
            {state.currentStep === 3 && (
              <Stack gap={20}>
                <Heading level={2}>Review & Confirm</Heading>
                <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Stack gap={16}>
                    <Stack gap={12}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Profile Information
                      </Text>
                      <Box paddingX={12}>
                        <Stack gap={8}>
                          <Stack direction="horizontal" justify="between">
                            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
